function solve(n, edges, k) {
    if (k === n) return 0;
    let maxTime = 0;
    for (const e of edges) {
        if (e[2] > maxTime) maxTime = e[2];
    }
    let low = 0, high = maxTime, ans = maxTime;
    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let comp = countComponents(n, edges, mid);
        if (comp >= k) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

function countComponents(n, edges, t) {
    const parent = new Array(n).fill().map((_, i) => i);
    const rank = new Array(n).fill(0);
    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]]; // Path compression
            x = parent[x];
        }
        return x;
    }
    function union(x, y) {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX === rootY) return;
        if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else {
            parent[rootX] = rootY;
            if (rank[rootX] === rank[rootY]) {
                rank[rootY]++;
            }
        }
    }
    for (const [u, v, time] of edges) {
        if (time > t) {
            union(u, v);
        }
    }
    let count = 0;
    for (let i = 0; i < n; i++) {
        if (find(i) === i) count++;
    }
    return count;
}
