function countComponents(n, edges, t) {
    const parent = new Array(n).fill().map((_, i) => i);
    const rank = new Array(n).fill(0);
    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]]; // Path compression
            x = parent[x];
        }
        return x;
    }
    function union(x, y) {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX === rootY) return;
        if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
