using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (k == n) return 0;
    long long max_time = 0;
    for (auto& e : edges) {
        max_time = max(max_time, e[2]);
    }
    long long low = 0, high = max_time;
    long long ans = max_time;
    while (low <= high) {
        long long mid = (low + high) / 2;
        long long comp = count_components(n, edges, mid);
        if (comp >= k) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

long long count_components(long long n, vector<vector<long long>> edges, long long t) {
    vector<long long> parent(n, 0);
    vector<long long> rank(n, 0);
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
    }
    for (auto& e : edges) {
        if (e[2] > t) {
            long long u = e[0];
            long long v = e[1];
            long long root_u = find(parent, u);
            long long root_v = find(parent, v);
            if (root_u != root_v) {
                if (rank[root_u] > rank[root_v]) {
                    parent[root_v] = root_u;
                } else {
                    parent[root_u] = root_v;
                    if (rank[root_u] == rank[root_v]) {
                        rank[root_v]++;
                    }
                }
            }
        }
    }
    long long count = 0;
    for (long long i = 0; i < n; ++i) {
        if (find(parent, i) == i) {
            count++;
        }
    }
    return count;
